const express = require('express');
const mongoose = require('mongoose');
const app = express();
app.use(express.json());

mongoose.connect('mongodb://localhost/coupons', { useNewUrlParser: true, useUnifiedTopology: true });

const couponSchema = new mongoose.Schema({
    code: { type: String, unique: true },
    discount: Number,
    expiresAt: Date,
    used: { type: Boolean, default: false }
});

const Coupon = mongoose.model('Coupon', couponSchema);

app.post('/redeem', async (req, res) => {
    const { code } = req.body;

    const session = await mongoose.startSession();
    session.startTransaction();

    try {
        const coupon = await Coupon.findOne({ code }).session(session);
        if (!coupon) {
            throw new Error('Coupon not found');
        }
        if (coupon.used) {
            throw new Error('Coupon already used');
        }
        if (coupon.expiresAt < new Date()) {
            throw new Error('Coupon expired');
        }

        coupon.used = true;
        await coupon.save({ session });

        await session.commitTransaction();
        res.status(200).json({ message: 'Coupon redeemed', discount: coupon.discount });
    } catch (error) {
        await session.abortTransaction();
        res.status(400).json({ error: error.message });
    } finally {
        session.endSession();
    }
});

app.listen(3000, () => {
    console.log('Server running on port 3000');
});